<?php
namespace App\Http\Controllers;use App\Models\{WorkerPayoutReview,WorkerPayoutReviewEvidence};use App\Services\Finance\WorkerPayoutEvidenceService;use Illuminate\Http\Request;
class WorkerPayoutEvidenceController extends Controller{public function upload(Request $r,WorkerPayoutReview $review,WorkerPayoutEvidenceService $s){abort_unless($review->worker_id===$r->user()->id,403);$d=$r->validate(['file'=>'required|file|max:10240|mimetypes:application/pdf','evidence_type'=>'required|in:identity_document,tax_document,payout_document,other']);$s->uploadEvidence($review,$r->user(),$d['file'],$d['evidence_type']);return back()->with('status','Private evidence uploaded. Review is not approved automatically.');}public function download(Request $r,WorkerPayoutReviewEvidence $evidence,WorkerPayoutEvidenceService $s){return $s->downloadEvidence($evidence,$r->user());}}
